const NZT_OFFSET = 12; // NZST (UTC+12) — DST ended April 6 2026

function toNZTDateStr(date) {
  const nzt = new Date(date.getTime() + NZT_OFFSET * 3600000);
  return nzt.toISOString().slice(0, 10);
}

function parseNZTStr(s) {
  // "2026-03-10 09:00" stored as NZT — parse back to UTC
  if (!s || s === 'PENDING') return null;
  const cleaned = s.trim().replace(' ', 'T');
  return new Date(cleaned + ':00+12:00');
}

function normalizePhone(phone) {
  if (!phone) return null;
  const c = phone.replace(/[\s\-\(\)]/g, '');
  if (c.startsWith('0')) return '+64' + c.slice(1);
  if (c.startsWith('+64')) return c;
  return null;
}

