const DAILY_CAP = 50;
const PER_RUN_CAP = 25;   // max new initial sends per run
const TOTAL_RUN_CAP = 25; // hard cap on total messages sent per run (initial + F1 + F2)

const now = new Date();

// ── Send window gate: Mon–Fri 9:00am–4:30pm NZT only ──
const nztNow = new Date(now.getTime() + NZT_OFFSET * 3600000);
const nztHour = nztNow.getUTCHours();
const nztMinute = nztNow.getUTCMinutes();
const nztDay = nztNow.getUTCDay(); // 0=Sun, 1=Mon…5=Fri, 6=Sat
const isWeekday = nztDay >= 1 && nztDay <= 5;
const afterStart = nztHour >= 9;
const beforeEnd = nztHour < 16 || (nztHour === 16 && nztMinute <= 30);
if (!isWeekday || !afterStart || !beforeEnd) return [];

const todayNZT = toNZTDateStr(now);
const rows = $input.all();

// Count today's initial sends — includes PENDING rows (attempted sends count toward daily cap)
let todaySentCount = 0;
for (const item of rows) {
  const g = (item.json['Initial Sent'] || '').trim();
  if (!g) continue;
  if (g === 'PENDING') {
    todaySentCount++;
    continue;
  }
  try {
    const sentDate = toNZTDateStr(parseNZTStr(g));
    if (sentDate === todayNZT) todaySentCount++;
  } catch(e) {}
}

const remaining = Math.max(0, DAILY_CAP - todaySentCount);
const initialCap = Math.min(remaining, PER_RUN_CAP);

const queue = [];

// --- Initial sends ---
let initialCount = 0;
for (const item of rows) {
  if (initialCount >= initialCap) break;
  const r = item.json;
  const leadType = (r['Type'] || '').trim();
  if (!MESSAGE_TEMPLATES[leadType]) continue;
  const status = (r['Status'] || '').trim();
  const g = (r['Initial Sent'] || '').trim();
  if (g || status === 'Opted Out') continue;
  const mobile = (r['Mobile'] || '').trim();
  const phone = normalizePhone(mobile);
  if (!phone) continue;
  const name = ((r['Name'] || '').split(' ')[0]) || 'there';
  const variant = Math.random() < 0.7 ? 'A' : 'B';
  const templates = MESSAGE_TEMPLATES[leadType][variant];
  queue.push({
    name, phone_e164: phone, original_mobile: mobile,
    message: templates.initial.replace('{name}', name),
    ts_col_name: 'Initial Sent', msg_col_name: 'Initial Message',
    variant
  });
  initialCount++;
}

// --- Followup 1 (3h+ after initial confirmed delivery) ---
for (const item of rows) {
  const r = item.json;
  const leadType = (r['Type'] || '').trim();
  if (!MESSAGE_TEMPLATES[leadType]) continue;
  const status = (r['Status'] || '').trim();
  const g = (r['Initial Sent'] || '').trim();
  const i = (r['F1 Sent'] || '').trim();
  const replied = (r['Replied'] || '').trim();
  if (!g || g === 'PENDING' || i || replied === 'TRUE' || status === 'Opted Out') continue;
  const gTime = parseNZTStr(g);
  if (!gTime) continue;
  const hoursAgo = (now - gTime) / 3600000;
  if (hoursAgo < 3) continue;
  const mobile = (r['Mobile'] || '').trim();
  const phone = normalizePhone(mobile);
  if (!phone) continue;
  const name = ((r['Name'] || '').split(' ')[0]) || 'there';
  const variant = (r['Variant'] || 'A').trim();
  const templates = MESSAGE_TEMPLATES[leadType][variant] || MESSAGE_TEMPLATES[leadType]['A'];
  queue.push({
    name, phone_e164: phone, original_mobile: mobile,
    message: templates.f1.replace('{name}', name),
    ts_col_name: 'F1 Sent', msg_col_name: 'F1 Message'
  });
}

// --- Followup 2 (21h+ after F1 confirmed delivery) ---
for (const item of rows) {
  const r = item.json;
  const leadType = (r['Type'] || '').trim();
  if (!MESSAGE_TEMPLATES[leadType]) continue;
  const status = (r['Status'] || '').trim();
  const i = (r['F1 Sent'] || '').trim();
  const k = (r['F2 Sent'] || '').trim();
  const replied = (r['Replied'] || '').trim();
  if (!i || i === 'PENDING' || k || replied === 'TRUE' || status === 'Opted Out') continue;
  const iTime = parseNZTStr(i);
  if (!iTime) continue;
  const hoursAgo = (now - iTime) / 3600000;
  if (hoursAgo < 21) continue;
  const mobile = (r['Mobile'] || '').trim();
  const phone = normalizePhone(mobile);
  if (!phone) continue;
  const name = ((r['Name'] || '').split(' ')[0]) || 'there';
  const variant = (r['Variant'] || 'A').trim();
  const templates = MESSAGE_TEMPLATES[leadType][variant] || MESSAGE_TEMPLATES[leadType]['A'];
  queue.push({
    name, phone_e164: phone, original_mobile: mobile,
    message: templates.f2.replace('{name}', name),
    ts_col_name: 'F2 Sent', msg_col_name: 'F2 Message'
  });
}

return queue.slice(0, TOTAL_RUN_CAP).map(item => ({ json: item }));

const item = $('Split Each Lead').item.json;
const output = { Mobile: item.original_mobile };
output[item.ts_col_name] = 'PENDING';
output[item.msg_col_name] = item.message;
if (item.variant) output['Variant'] = item.variant;
return [{ json: output }];

